sql:
SELECT COUNT(*) AS active_ads_count
FROM ads
WHERE is_active = 1;

SELECT advertiser_name 
FROM advertisers 
WHERE advertiser_id = 0;

SELECT SUM(clicks) AS total_clicks
FROM ad_performance
WHERE ad_id = 1;

SELECT ad_id, title, message, created_at
FROM ads
ORDER BY created_at DESC;

SELECT DISTINCT title, message, thumbnail
FROM ads
WHERE political = 1 AND is_active = 1;

SELECT SUM(budget) AS total_budget
FROM ads
WHERE political = 0 AND budget > 500.0;
